What does this program print?

```cpp
#include <iostream>
int square(int x) { return x * x; }
int cube(int x) { return x * x * x; }
int main() {
    int (*f)(int) = square;
    std::cout << f(3) << "\n";
    f = cube;
    std::cout << f(3) << "\n";
}
```

What does this program print?

```cpp
#include <iostream>
using Op = int (*)(int, int);
int add(int a, int b) { return a + b; }
int run(Op f, int x, int y) { return f(x, y); }
int main() {
    std::cout << run(add, 10, 5) << "\n";
    std::cout << run(add, 3, 7) << "\n";
}
```
